import SwiftUI

struct BlurAnimatableModifier: AnimatableModifier {
    var blur: CGFloat
    var animatableData: CGFloat {
        get { blur }
        set { blur = newValue }
    }
    func body(content: Content) -> some View {
        content.blur(radius: blur)
    }
}

struct BlurDemo: View {
    @State private var blur: CGFloat = 0
    var body: some View {
        VStack {
            Image(systemName: "star.fill")
                .resizable().frame(width: 100, height: 100)
                .modifier(BlurAnimatableModifier(blur: blur))
                .gesture(DragGesture().onChanged { value in
                    blur = min(max(0, value.translation.height / 5), 20)
                })
            Text("Drag to blur")
        }
    }
}

import SwiftUI

struct WaterfallLayout: Layout {
    func sizeThatFits(proposal: ProposedViewSize, subviews: Subviews, cache: inout ()) -> CGSize {
        let width = proposal.width ?? 300
        let columnCount = 2
        var heights = Array(repeating: CGFloat(0), count: columnCount)
        for (i, subview) in subviews.enumerated() {
            let col = i % columnCount
            heights[col] += subview.sizeThatFits(.unspecified).height
        }
        return CGSize(width: width, height: heights.max() ?? 0)
    }
    func placeSubviews(in bounds: CGRect, proposal: ProposedViewSize, subviews: Subviews, cache: inout ()) {
        let columnCount = 2
        let columnWidth = bounds.width / CGFloat(columnCount)
        var yOffsets = Array(repeating: bounds.minY, count: columnCount)
        for (i, subview) in subviews.enumerated() {
            let col = i % columnCount
            let x = bounds.minX + CGFloat(col) * columnWidth
            let y = yOffsets[col]
            let size = subview.sizeThatFits(.unspecified)
            subview.place(at: CGPoint(x: x + columnWidth/2, y: y + size.height/2), anchor: .center, proposal: ProposedViewSize(width: columnWidth, height: size.height))
            yOffsets[col] += size.height
        }
    }
}

struct WaterfallDemo: View {
    @State private var items = (1...10).map { _ in CGFloat.random(in: 60...150) }
    var body: some View {
        VStack {
            WaterfallLayout {
                ForEach(items.indices, id: \.self) { i in
                    Rectangle().fill(Color.blue)
                        .frame(height: items[i])
                        .animation(.easeInOut, value: items)
                }
            }
            Button("Add") { withAnimation { items.append(CGFloat.random(in: 60...150)) } }
        }
    }
}

import SwiftUI

struct MorphingShape: Shape {
    var morph: CGFloat
    var animatableData: CGFloat {
        get { morph }
        set { morph = newValue }
    }
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let corner = morph * min(rect.width, rect.height) / 2
        path.addRoundedRect(in: rect, cornerSize: CGSize(width: corner, height: corner))
        return path
    }
}

struct MorphDemo: View {
    @State private var morph: CGFloat = 0
    var body: some View {
        VStack {
            MorphingShape(morph: morph)
                .fill(Color.purple)
                .frame(width: 120, height: 120)
                .onTapGesture { withAnimation(.easeInOut(duration: 1)) { morph = morph == 0 ? 1 : 0 } }
            Text("Tap to morph")
        }
    }
}

import SwiftUI

struct CarouselLayout: Layout {
    func sizeThatFits(proposal: ProposedViewSize, subviews: Subviews, cache: inout ()) -> CGSize {
        CGSize(width: 300, height: 300)
    }
    func placeSubviews(in bounds: CGRect, proposal: ProposedViewSize, subviews: Subviews, cache: inout ()) {
        let center = CGPoint(x: bounds.midX, y: bounds.midY)
        let count = subviews.count
        let angleStep = 2 * .pi / CGFloat(max(count, 1))
        let radius: CGFloat = 100
        for (i, subview) in subviews.enumerated() {
            let angle = angleStep * CGFloat(i) - .pi/2
            let x = center.x + cos(angle) * radius
            let y = center.y + sin(angle) * radius
            subview.place(at: CGPoint(x: x, y: y), anchor: .center, proposal: .unspecified)
        }
    }
}

struct CarouselDemo: View {
    @State private var count = 8
    var body: some View {
        VStack {
            CarouselLayout {
                ForEach(0..<count, id: \.self) { i in
                    Circle().fill(Color.orange)
                        .frame(width: 40, height: 40)
                        .overlay(Text("\(i+1)").foregroundColor(.white))
                }
            }
            Button("Add") { withAnimation { count += 1 } }
        }
    }
}

import SwiftUI

struct ColorAnimatableModifier: AnimatableModifier {
    var progress: Double
    var animatableData: Double {
        get { progress }
        set { progress = newValue }
    }
    func body(content: Content) -> some View {
        let color = Color(red: 1-progress, green: 0, blue: progress)
        content.background(color)
    }
}

struct ColorAnimationDemo: View {
    @State private var progress: Double = 0
    var body: some View {
        VStack {
            Rectangle().frame(width: 120, height: 120)
                .modifier(ColorAnimatableModifier(progress: progress))
                .onTapGesture { withAnimation(.linear(duration: 1)) { progress = progress == 0 ? 1 : 0 } }
            Text("Tap to animate color")
        }
    }
}

